        const schedule = engrid_ENGrid.getUrlParameter("engrid_ecard.schedule");
        const scheduleField = engrid_ENGrid.getField("ecard.schedule");
        const name = engrid_ENGrid.getUrlParameter("engrid_ecard.name");
