    debounceWithImmediate(func, timeout = 1000) {
        let timer;
        let firstEvent = true;
        return (...args) => {
            clearTimeout(timer);
            if (firstEvent) {
                func.apply(this, args);
                firstEvent = false;
            }
            timer = setTimeout(() => {
                func.apply(this, args);
                firstEvent = true;
            }, timeout);
        };
    }
